#include <iostream>
#include <string>
#include <vector>
#include <cstring>
#include <cctype>

// The countVowels function, identical to the one in 4796.cpp for testing.
int countVowels(const char* str) {
    int count = 0;
    if (str == nullptr) {
        return 0;
    }
    for (int i = 0; str[i] != '\0'; ++i) {
        char currentChar = str[i];
        if (currentChar == 'a' || currentChar == 'A' ||
            currentChar == 'e' || currentChar == 'E' ||
            currentChar == 'i' || currentChar == 'I' ||
            currentChar == 'o' || currentChar == 'O' ||
            currentChar == 'u' || currentChar == 'U') {
            count++;
        }
    }
    return count;
}

int main() {
    std::vector<std::pair<const char*, int>> tests = {
        {"Hello World!", 3},
        {"Programming is FUN", 5},
        {"AEIOUaeiou", 10},
        {"Rhythm", 0},
        {"", 0}
    };

    for (const auto& test : tests) {
        char buffer[256]; 
        if (test.first != nullptr) {
            strcpy(buffer, test.first);
        } else {
            buffer[0] = '\0'; 
        }

        int result = countVowels(buffer);
        std::cout << "Number of vowels: " << result << std::endl;
    }
    return 0;
}
